import { useState, useEffect } from 'react';
import { useForm } from '@inertiajs/react';

const LOGO = "data:image/svg+xml;base64,";

const SLIDES = [
    {
        icon: "🧠",
        headline: "Intelligent at Its Core",
        sub: "AI-powered analysis and proposal generation to support smarter organizational decisions.",
    },
    {
        icon: "🌐",
        headline: "Speak Every Language",
        sub: "Break barriers instantly — translate documents, emails, and chats in real time.",
    },
    {
        icon: "👥",
        headline: "HR & Recruitment, Simplified",
        sub: "From hiring pipelines to payroll and role management — all in one unified platform.",
    },
    {
        icon: "⚡",
        headline: "Work Without Friction",
        sub: "Smart mail, AI chat, employee assignments — built for every level of your team.",
    },
];

export default function Login() {
    const { data, setData, post, processing, errors, clearErrors } = useForm({
        email: '',
        password: '',
        remember: false,
    });

    const [clientErrors, setClientErrors] = useState({ email: '', password: '' });
    const [showPass, setShowPass] = useState(false);
    const [slide, setSlide] = useState(0);
    const [fading, setFading] = useState(false);

    useEffect(() => {
        const timer = setInterval(() => {
            setFading(true);
            setTimeout(() => {
                setSlide(s => (s + 1) % SLIDES.length);
                setFading(false);
            }, 400);
        }, 4000);
        return () => clearInterval(timer);
    }, []);

    const validate = () => {
        const newErrors = { email: '', password: '' };
        let isValid = true;
        if (!data.email.trim()) { newErrors.email = 'Please fill in your email address.'; isValid = false; }
        if (!data.password.trim()) { newErrors.password = 'Please fill in your password.'; isValid = false; }
        setClientErrors(newErrors);
        return isValid;
    };

    const submit = (e) => {
        e.preventDefault();
        clearErrors();
        if (!validate()) return;
        post('/login');
    };

    const goTo = (i) => {
        if (i === slide) return;
        setFading(true);
        setTimeout(() => { setSlide(i); setFading(false); }, 400);
    };

    return (
        <div style={styles.page}>
            <div style={styles.orb1} />
            <div style={styles.orb2} />
            <div style={styles.orb3} />
            <div style={styles.gridOverlay} />

            <div style={styles.card}>
                {/* LEFT PANEL */}
                <div style={styles.leftPanel}>
                    <div style={styles.leftInner}>

                        {/* Badge */}
                        <div style={styles.badge}>
                            <span style={styles.badgeDot} />
                            <span style={styles.badgeText}>AI-Powered Platform</span>
                        </div>

                        {/* Illustration — fixed */}
                        <div style={styles.illustWrap}>
                            <img
                                src="/images/login-illustration.svg"
                                alt="Secure Login"
                                style={styles.illus}
                            />
                        </div>

                        {/* Animated text */}
                        <div style={{
                            ...styles.slideText,
                            opacity: fading ? 0 : 1,
                            transform: fading ? 'translateY(8px)' : 'translateY(0)',
                        }}>
                            <span style={styles.slideIcon}>{SLIDES[slide].icon}</span>
                            <p style={styles.leftTitle}>{SLIDES[slide].headline}</p>
                            <p style={styles.leftSub}>{SLIDES[slide].sub}</p>
                        </div>

                        {/* Dots */}
                        <div style={styles.dots}>
                            {SLIDES.map((_, i) => (
                                <span
                                    key={i}
                                    onClick={() => goTo(i)}
                                    style={i === slide ? {...styles.dot, ...styles.dotActive} : styles.dot}
                                />
                            ))}
                        </div>
                    </div>
                </div>

                {/* RIGHT PANEL */}
                <div style={styles.rightPanel}>
                    <div style={styles.formWrap}>

                        {/* Logo — centered above heading */}
                        <div style={styles.logoArea}>
                            <img src={LOGO} alt="VibeMe.AI" style={styles.logoImg} />
                        </div>

                        <h2 style={styles.heading}>Welcome back</h2>
                        <p style={styles.subHeading}>Sign in to continue your journey</p>

                        <form onSubmit={submit} style={styles.form}>
                            {/* Email */}
                            <div style={styles.fieldGroup}>
                                <label style={styles.label}>Email</label>
                                <div style={styles.inputWrap}>
                                    <svg style={styles.fieldIcon} viewBox="0 0 20 20" fill="none">
                                        <rect x="2" y="4" width="16" height="12" rx="2" stroke="#7eb8f5" strokeWidth="1.4"/>
                                        <path d="M2.5 6.5L10 11l7.5-4.5" stroke="#7eb8f5" strokeWidth="1.4" strokeLinecap="round"/>
                                    </svg>
                                    <input
                                        type="email"
                                        value={data.email}
                                        onChange={(e) => { setData('email', e.target.value); setClientErrors(p => ({...p, email: ''})); }}
                                        placeholder="you@example.com"
                                        style={styles.input}
                                        onFocus={e => e.target.style.borderColor='rgba(59,154,224,0.7)'}
                                        onBlur={e => e.target.style.borderColor='rgba(255,255,255,0.1)'}
                                    />
                                </div>
                                {(clientErrors.email || errors.email) && (
                                    <p style={styles.errMsg}>{clientErrors.email || errors.email}</p>
                                )}
                            </div>

                            {/* Password */}
                            <div style={styles.fieldGroup}>
                                <label style={styles.label}>Password</label>
                                <div style={styles.inputWrap}>
                                    <svg style={styles.fieldIcon} viewBox="0 0 20 20" fill="none">
                                        <rect x="5" y="9" width="10" height="8" rx="2" stroke="#7eb8f5" strokeWidth="1.4"/>
                                        <path d="M7 9V7a3 3 0 0 1 6 0v2" stroke="#7eb8f5" strokeWidth="1.4" strokeLinecap="round"/>
                                    </svg>
                                    <input
                                        type={showPass ? 'text' : 'password'}
                                        value={data.password}
                                        onChange={(e) => { setData('password', e.target.value); setClientErrors(p => ({...p, password: ''})); }}
                                        placeholder="••••••••"
                                        style={styles.input}
                                        onFocus={e => e.target.style.borderColor='rgba(59,154,224,0.7)'}
                                        onBlur={e => e.target.style.borderColor='rgba(255,255,255,0.1)'}
                                    />
                                    <button
                                        type="button"
                                        onClick={() => setShowPass(p => !p)}
                                        style={styles.eyeBtn}
                                        aria-label="Toggle password"
                                    >
                                        {showPass ? (
                                            <svg width="16" height="16" viewBox="0 0 20 20" fill="none">
                                                <path d="M3 3l14 14M8.5 8.5A2.5 2.5 0 0 0 12.5 12.5" stroke="#7eb8f5" strokeWidth="1.4" strokeLinecap="round"/>
                                                <path d="M6.3 5.3C4.1 6.6 2.5 8.6 2 10c1.2 3.4 4.7 6 8 6a9 9 0 0 0 3.7-.8M10 4c3.3 0 6.8 2.6 8 6-.4 1-1 2-1.9 2.9" stroke="#7eb8f5" strokeWidth="1.4" strokeLinecap="round"/>
                                            </svg>
                                        ) : (
                                            <svg width="16" height="16" viewBox="0 0 20 20" fill="none">
                                                <ellipse cx="10" cy="10" rx="8" ry="4.5" stroke="#7eb8f5" strokeWidth="1.4"/>
                                                <circle cx="10" cy="10" r="2.5" stroke="#7eb8f5" strokeWidth="1.4"/>
                                            </svg>
                                        )}
                                    </button>
                                </div>
                                {(clientErrors.password || errors.password) && (
                                    <p style={styles.errMsg}>{clientErrors.password || errors.password}</p>
                                )}
                            </div>

                            {/* Remember + Forgot */}
                            <div style={styles.rowBetween}>
                                <label style={styles.rememberLabel}>
                                    <input
                                        type="checkbox"
                                        checked={data.remember}
                                        onChange={(e) => setData('remember', e.target.checked)}
                                        style={styles.checkbox}
                                    />
                                    Remember me
                                </label>
                                <a href="/forgot-password" style={styles.forgotLink}>Forgot password?</a>
                            </div>

                            {/* Submit */}
                            <button
                                type="submit"
                                disabled={processing}
                                style={{
                                    ...styles.submitBtn,
                                    opacity: processing ? 0.6 : 1,
                                    cursor: processing ? 'not-allowed' : 'pointer',
                                }}
                            >
                                {processing ? 'Signing in...' : 'Sign In'}
                            </button>
                        </form>

                        <p style={styles.copyright}>© 2026 VibeMe.AI</p>
                    </div>
                </div>
            </div>
        </div>
    );
}

